const body = $input.first().json.body;
const shipmentId = body.shipmentId;
const rateId = body.rateId || body.shippoRateId;

if (!shipmentId || !rateId) {
  throw new Error('缺少必要参数: shipmentId 和 rateId');
}

return { shipmentId, rateId };

const shipment = $input.first().json;
const input = $('Validate Input').first().json;

if (!shipment || !shipment.shippo_object_id) {
  throw new Error('订单不存在或未生成报价');
}

if (shipment.status !== 'draft' && shipment.status !== 'pending_payment') {
  throw new Error('订单状态不允许购买 label，当前状态: ' + shipment.status);
}

return {
  shipmentId: shipment.id,
  shippoObjectId: shipment.shippo_object_id,
  rateId: input.rateId || shipment.shippo_rate_id
};

const transaction = $input.first().json;
const prev = $('Validate Shipment').first().json;

if (transaction.status !== 'SUCCESS') {
  throw new Error('购买 label 失败: ' + JSON.stringify(transaction.messages));
}

const trackingNumber = transaction.tracking_number;
const labelUrl = transaction.label_url;
const trackingUrl = transaction.tracking_url_provider;

return {
  shipmentId: prev.shipmentId,
  trackingNumber,
  labelUrl,
  trackingUrl,
  transactionId: transaction.object_id,
  carrier: transaction.rate?.provider || 'Unknown',
  serviceName: transaction.rate?.servicelevel?.name || '',
  amount: parseFloat(transaction.rate?.amount || 0)
};

const shipment = $('Update Shipment').first().json;
const transaction = $('Parse Transaction').first().json;
const origShipment = $('Get Shipment').first().json;

return {
  contactEmail: origShipment.sender_email || shipment.sender_email || `demo_${shipment.id}@cargoflow.test`,
  contactName: origShipment.sender_name || shipment.sender_name || `Customer #${shipment.id}`,
  contactPhone: origShipment.sender_phone || shipment.sender_phone || '',
  orderShipmentId: shipment.id,
  orderAmount: shipment.quote_amount || 0,
  orderRoute: `${shipment.from_address || origShipment.from_address} → ${shipment.to_address || origShipment.to_address}`,
  orderCarrier: `${shipment.carrier || ''} ${shipment.service_name || ''}`.trim() || 'Unknown',
  orderDate: new Date().toISOString().split('T')[0],
  trackingNumber: transaction.trackingNumber || shipment.tracking_number
};

const shipment = $('Update Shipment').first().json;
const transaction = $('Parse Transaction').first().json;
const origShipment = $('Get Shipment').first().json;
const nameParts = (origShipment.sender_name || shipment.sender_name || 'CargoFlow Customer').trim().split(' ');

return {
  firstName: nameParts[0] || 'CargoFlow',
  lastName: nameParts.slice(1).join(' ') || 'Customer',
  email: origShipment.sender_email || shipment.sender_email || '',
  phone: origShipment.sender_phone || shipment.sender_phone || '',
  shipmentId: shipment.id,
  carrier: transaction.carrier || shipment.carrier || 'Unknown',
  serviceName: transaction.serviceName || shipment.service_name || '',
  amount: shipment.quote_amount || 0,
  trackingNumber: transaction.trackingNumber || shipment.tracking_number || '',
  fromAddress: origShipment.from_address || shipment.from_address || '',
  toAddress: origShipment.to_address || shipment.to_address || '',
  orderDate: new Date().toISOString().split('T')[0]
};

const ghlResponse = $input.first().json;
const buildData = $('GHL - Build Contact Data').first().json;

// GHL returns contact object on create; on duplicate it may return 400 with existing contact id
let contactId = ghlResponse.contact?.id || ghlResponse.id || null;

return {
  contactId,
  shipmentId: buildData.shipmentId,
  carrier: buildData.carrier,
  serviceName: buildData.serviceName,
  amount: buildData.amount,
  trackingNumber: buildData.trackingNumber,
  fromAddress: buildData.fromAddress,
  toAddress: buildData.toAddress,
  orderDate: buildData.orderDate
};

const shipment = $('Update Shipment').first().json;
const transaction = $('Parse Transaction').first().json;

return {
  success: true,
  shipmentId: shipment.id,
  status: shipment.status,
  trackingNumber: transaction.trackingNumber,
  labelUrl: transaction.labelUrl,
  trackingUrl: transaction.trackingUrl,
  carrier: transaction.carrier,
  serviceName: transaction.serviceName,
  message: `Label purchased successfully. Tracking: ${transaction.trackingNumber}`
};
